package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = new CSVFormat(',', '"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "\\N",
                new Object[]{"Header1", "Header2"}, new String[]{"Comment1", "Comment2"}, false, true, false, true, false);
    }

    @Test
    public void testGetIgnoreSurroundingSpaces() throws Exception {
        // Given
        boolean expected = true;

        // When
        boolean result = csvFormat.getIgnoreSurroundingSpaces();

        // Then
        assertEquals(expected, result);
    }

    // Helper method to set private field using reflection
    private void setPrivateField(Object targetObject, String fieldName, Object newValue) throws Exception {
        Field field = targetObject.getClass().getDeclaredField(fieldName);
        field.setAccessible(true);
        field.set(targetObject, newValue);
    }
}
